function solve(n, edges) {
    // Build the adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push({ to: v, weight: w });
    }

    // Dijkstra's algorithm with a priority queue
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    const pq = new PriorityQueue((a, b) => a.cost - b.cost);
    pq.enqueue({ node: 0, cost: 0, switchUsed: false });

    while (!pq.isEmpty()) {
        const { node, cost, switchUsed } = pq.dequeue();
        if (node === n - 1) return cost;
        if (cost > dist[node]) continue;

        // Check if we can use the switch at this node
        if (!switchUsed) {
            // Option 1: Use the switch (reverse the edge)
            for (const { to, weight } of adj[node]) {
                const newCost = cost + 2 * weight;
                if (newCost < dist[to]) {
                    dist[to] = newCost;
                    pq.enqueue({ node: to, cost: newCost, switchUsed: true });
                }
            }
        }

        // Option 2: Don't use the switch (normal edge)
        for (const { to, weight } of adj[node]) {
            const newCost = cost + weight;
            if (newCost < dist[to]) {
                dist[to] = newCost;
                pq.enqueue({ node: to, cost: newCost, switchUsed: false });
            }
        }
    }

    return -1;
}

